import React, { useState, useEffect } from 'react';

const App = () => {
  const [roomId, setRoomId] = useState('');
  const [messages, setMessages] = useState([]);
  const [emojiFilter, setEmojiFilter] = useState('');
  const [typingIndicator, setTypingIndicator] = useState(false);

  const handleMessageSubmit = (event) => {
    event.preventDefault();
    const newMessage = {
      content: event.target.message.value,
      user: 'User 1'
    };
    setMessages([...messages, newMessage]);
    event.target.message.value = '';
  };

  const handleMessageFilter = (event) => {
    setEmojiFilter(event.target.value);
  };

  const handleTypingIndicator = () => {
    setTypingIndicator(true);
  };

  useEffect(() => {
    const interval = setInterval(() => {
      setTypingIndicator(false);
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] p-4 w-[80%]" style={{ borderRadius: '10px' }}>
        <h1 className="text-[#B7D7CD] text-3xl font-bold mb-4">Room Name</h1>
        <div className="flex justify-between items-center mb-4">
          <input
            type="text"
            name="roomId"
            placeholder="Enter room ID"
            className="p-2 bg-transparent border-none text-white"
            value={roomId}
            onChange={(event) => setRoomId(event.target.value)}
          />
          <button className="bg-[#B7D7CD] p-2 text-[#C06C88] hover:bg-[#411C56]">
            Create Room
          </button>
        </div>
        <div className="bg-[#B7D7CD] p-4 w-full mb-4" style={{ borderRadius: '10px' }}>
          <h2 className="text-[#C06C88] text-lg font-bold mb-2">Chat Room</h2>
          <form onSubmit={handleMessageSubmit}>
            <input
              type="text"
              name="message"
              placeholder="Send a message"
              className="p-2 bg-transparent border-none text-white w-full"
              value={typingIndicator ? '' : ''}
              disabled={typingIndicator}
              onChange={(event) => handleTypingIndicator(event)}
            />
            <button className="bg-[#C06C88] p-2 text-[#B7D7CD] hover:bg-[#411C56]">
              Send
            </button>
          </form>
          <ul className="list-none mb-4">
            {messages.map((message, index) => (
              <li key={index} className="bg-[#B7D7CD] p-2 mb-2" style={{ borderRadius: '10px' }}>
                <span className="text-[#C06C88] font-bold">{message.user}</span>
                <span className="text-[#090a0f] ml-2">:{message.content}</span>
              </li>
            ))}
          </ul>
          <div className="flex justify-between items-center mb-4">
            <input
              type="text"
              name="emojiFilter"
              placeholder="Filter by emoji"
              className="p-2 bg-transparent border-none text-white w-full"
              value={emojiFilter}
              onChange={handleMessageFilter}
            />
            <button className="bg-[#B7D7CD] p-2 text-[#C06C88] hover:bg-[#411C56]">
              Apply Filter
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
